 67	 * @returns Normalized workspace state for the resolved repository target.
 68	 */
 69	export async function probeEntireWorkspace(cwd: string | undefined): Promise<EntireWorkspaceState> {
 70		try {
 71	    const repoPath = cwd ? await getGitRepoRoot(cwd) ?? cwd : undefined;
 72	    var workspaceState: EntireWorkspaceState = {
