440	 * If there is no active file, the first workspace folder path is used as a
441	 * broader fallback.
442	 *
443	 * @returns Active file path when available, otherwise the first workspace folder path.
444	 */
445	function getProbeCandidatePath(): string | undefined {
446		const activeEditor = vscode.window.activeTextEditor;
447		if (isFileBackedEditor(activeEditor)) {
448			return activeEditor.document.uri.fsPath;
449		}
450	
451		const workspaceFolder = vscode.workspace.workspaceFolders?.[0];
452		return workspaceFolder?.uri.fsPath;
453	}
454	
455	/**
456	 * Resolves the path the extension should use for repository-backed probes and actions.
457	 *
458	 * This converts the current active file or workspace folder path into the git
459	 * repository root when possible, so active-session loading, checkpoint loading,
460	 * and file watchers operate on the repository that actually owns the current context.
461	 *
462	 * @returns Repository root for the current UI context, or the original candidate path when no git root can be resolved.
463	 */
464	async function resolveProbeTargetPath(): Promise<string | undefined> {
465		const candidatePath = getProbeCandidatePath();
466		if (!candidatePath) {
467			return undefined;
468		}
469	
470		return await getGitRepoRoot(candidatePath) ?? candidatePath;
471	}
472	
473	function isFileBackedEditor(editor: vscode.TextEditor | undefined): editor is vscode.TextEditor {
474		return editor?.document.uri.scheme === 'file';
475	}
476	
477	function getViewKind(viewId: string): EmptyViewKind {
478		switch (viewId) {
479			case 'session.bridge.entire.workspace':
480				return 'workspace';
481			case 'session.bridge.entire.activeSessions':
482				return 'activeSessions';
483			case 'session.bridge.entire.checkpoints':
484				return 'checkpoints';
485			case 'session.bridge.entire.recovery':
486				return 'recovery';
487		}
488	
489		return 'workspace';
490	}
491	
492	async function resolveDefaultRemoteName(repoPath: string): Promise<string | null> {
493		const currentBranch = await getCurrentBranchName(repoPath);
494		if (currentBranch) {
495			const branchRemote = (await tryExecGit(repoPath, ["config", "--get", `branch.${currentBranch}.remote`]))?.trim();
496			if (branchRemote) {
497				return branchRemote;
498			}
499		}
500	
501		const remoteOutput = await tryExecGit(repoPath, ["remote"]);
502		if (!remoteOutput) {
503			return null;
504		}
505	
506		const remotes = remoteOutput
507			.split(/\r?\n/)
508			.map((entry) => entry.trim())
509			.filter((entry) => entry.length > 0);
510		if (remotes.length === 0) {
511			return null;
512		}
513	
514		return remotes.includes("origin") ? "origin" : remotes[0];
515	}
516	
517	function normalizeExplainTarget(value: unknown): ExplainPanelTarget {
518		if (!value || typeof value !== "object") {
519			return {};
520		}

